var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。","ENG":"that you'll be with him, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called him to your office. He said he'd be here soon.","TWN":"做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"이런 자리까지 불러줘서 고맙군.","JPN":" こんな席にまで呼んでくれてありがとう。","ENG":" I appreciate you bringing me here.","TWN":"謝謝你找我過來。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그리고 이건 그간의 협력과 우정에 대한 표시로 받아줬으면 해.","JPN":" それと、これはこれまでの協力と友情の礼として受け取ってくれ。","ENG":" Here. Consider this a memento of our mutual appreciation and friendship.","TWN":"這是對於這段時間的合作和友情的一點心意，希望你可以收下。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"감자로 만든 에일이다. 올해는 수확량이 꽤 넉넉했거든.","JPN":" ジャガイモで作ったエールだ。今年は収穫量が結構多かったからな。","ENG":" It's spud ale. We had quite the harvest this year.","TWN":"這是用馬鈴薯釀造的麥酒，今年的收成很不錯呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그건 그렇고 여긴 언제나 경치가 좋아.","JPN":" ところで、ここはいつも景色がいいな。","ENG":" Aside from that, the view from here is always incredible.","TWN":"話說回來，不管什麼時候來，景色總是這麼棒。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"이런 높은 곳에서 도시의 전경을 내려다볼 수 있다니 부럽군. 우리 노르드나빅 국경의 언덕에서 내려다보는 경치와 비교해도 부족하지 않을 정도다.","JPN":" こんな高いところから都市の全景を見下ろすことができるとは羨ましいな。ノルドナビック国境の高台から見下ろす景色と比べても遜色がない。","ENG":"You're lucky to be able to see the entire city from up here. It's almost as good as viewing the Nordnavik landscape from a hilltop.","TWN":"真羨慕你可以在這裡欣賞全市的風景，和我們從諾爾德萊比國境之丘俯望的景色相比毫不遜色呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"물론 도시 건물의 야경이나 대자연의 풍경도 아름답지만, 내가 가장 즐기는 것은 새벽 굴뚝의 연기와 다리 위를 달리는 차들이야.","JPN":" もちろん都市の建物の夜景や大自然の風景も美しいが、私の目を一番楽しませてくれるのは夜明けに見える煙突の煙と橋の上を走る車だな。","ENG":"I like the city's nightscape and the natural scenery here, however, what I really enjoy is smoke coming from chimneys at dawn and cars crossing bridges.","TWN":"城市建築物的夜景，或是大自然的風景也很美，但我最喜歡的是清晨煙囪冒出的煙氣，與橋上奔馳的車輛。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"저렇게 부지런히 살아가는 사람들의 모습을 보고 있으면, 우리가 지켜내고 있는 평화가 얼마나 고귀한 것인가를 새삼 깨닫게 되지.","JPN":" あんなに真面目に生きていく人たちの姿を見ていると、我々が守っている平和がどれほど尊いものか改めて気付かされる。","ENG":" Seeing how people live diligently makes me realize how valuable the peace we are protecting is.","TWN":"因為看到大家努力生活的模樣，就會令我再次意識到，我們守護的和平是多麼地有價值。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"나로선 이런 광경을 더 오랫동안 볼 수 없다는 게 안타까운 심경이지만…","JPN":" 私としてはこういう光景をそう長い間見られないということが残念だが……","ENG":" However, it's a shame I won't be around to see much more of this for a long time, but...","TWN":"雖然我覺得很遺憾，無法再看久一點這樣的景色…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…오늘 나의 친구와 함께 잔을 나누는 기쁨에 비하면, 그런 안타까움은 아무것도 아니지.","JPN":" ……今日、私の友と杯を交わす喜びに比べれば、そんなものは残念なうちにも入らないな。","ENG":" ...It pales in comparison to the pleasure I felt sharing a glass with a friend today.","TWN":"…但今天與朋友一起小酌一杯的喜樂，更勝心中的遺憾。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"이런. 미리 묻는 걸 깜빡했군. 혹시 감자나 술에 알러지가 있진 않겠지?","JPN":" おっと。聞き忘れたな。もしかしてジャガイモや酒にアレルギーはないか？","ENG":" Oh my, I forgot to ask. You're not allergic to ale or potatoes, are you?","TWN":"糟糕，忘記先問一下，你應該不會對馬鈴薯或酒過敏吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};